public class Solution {
    public boolean isMatch(String s, String p) {
        int m = s.length(), n = p.length();
        boolean[][] dp = new boolean[m + 1][n + 1];
        dp[0][0] = true;

        for (int j = 1; j <= n; j++) {
            boolean isMatch = p.charAt(j - 1) == '*' && dp[0][j - 2];
            if (isMatch) {
                dp[0][j] = true;
            }
        }

        for (int i = 1; i <= m; i++) {
            for (int j = 1; j <= n; j++) {
                boolean isMatchCharOrDot = p.charAt(j - 1) == s.charAt(i - 1) || p.charAt(j - 1) == '.';
                if (isMatchCharOrDot) {
                    dp[i][j] = dp[i - 1][j - 1];
                } else if (p.charAt(j - 1) == '*') {
                    boolean isZeroPrecedingCharacter = dp[i][j - 2];
                    boolean isCurrentAndPreviousCharactersMatching = dp[i - 1][j] && (s.charAt(i - 1) == p.charAt(j - 2) || p.charAt(j - 2) == '.');
                    dp[i][j] = isZeroPrecedingCharacter || isCurrentAndPreviousCharactersMatching;
                }
            }
        }

        return dp[m][n];
    }
}

