public class Solution {
    public String countAndSay(int n) {
        if (n == 1) return "1";
        return computeCountAndSay(n-1, new StringBuilder(), 0);
    }

    private String computeCountAndSay(String previous, StringBuilder result, int i) {
        if (i >= previous.length()) {
            return result.toString();
        }
        int count = 1;
        while (i + 1 < previous.length() && previous.charAt(i+1) == previous.charAt(i)) {
            i++;
            count++;
        }
        result.append(count).append(previous.charAt(i));
        return computeCountAndSay(previous, result, i + 1);
    }
}

