    private int computeJump(int[] nums, int jumps, int currentEnd) {
        int currentFarthest = 0;

        for (int i = 0; i < nums.length - 1 && i <= currentEnd; i++) {
            currentFarthest = Math.max(currentFarthest, i + nums[i]);
            if (i == currentEnd) {
                jumps++;
                currentEnd = currentFarthest;
            }
        }

        return jumps;
    }
}

