    private boolean computeCanJump(int[] nums, int index) {
        if (index >= nums.length - 1) return true;
        for (int i = index; i < Math.min(index + nums[index], nums.length); ++i) {
            if (computeCanJump(nums, i)) return true;
        }
        return false;
    }
}

