                boolean fromLeft = j > 0 ? dp[i][j - 1] && s2.charAt(j - 1) == s3.charAt(i + j - 1) : false;
                dp[i][j] = fromTop || fromLeft;
            }
        }

        return dp[m][n];
    }
}

