    public ListNode insertionSortList(ListNode head) {
        ListNode dummy = new ListNode(0);
        ListNode cur;

        while (head != null) {
            // Find the correct position to insert 'head'
            findInsertionPosition(dummy, head);

            // Move to the next node
            head = head.next;
        }

        return dummy.next;
    }

    private void findInsertionPosition(ListNode dummy, ListNode target) {
        ListNode cur = dummy;

        while (cur.next != null && cur.next.val < target.val) {
            cur = cur.next;
        }

        // Insert 'target' into the correct position
        insertNode(cur, target);
    }

    private void insertNode(ListNode prev, ListNode nodeToInsert) {
        ListNode temp = prev.next;
        prev.next = nodeToInsert;
        nodeToInsert.next = temp;
    }
}

