import java.util.List;
import java.util.Queue;

public class Solution {
    public boolean canFinish(int numCourses, int[][] prerequisites) {
        List<List<Integer>> adj = new ArrayList<>(numCourses);
        int[] inDegree = new int[numCourses];

        for (int i = 0; i < numCourses; i++)
            adj.add(new ArrayList<>());

        // Build the adjacency list and calculate in-degrees
        for (int[] p : prerequisites) {
            adj.get(p[1]).add(p[0]);
            inDegree[p[0]]++;
        }

        Queue<Integer> q = new LinkedList<>();

        // Enqueue all nodes with zero in-degree
        for (int i = 0; i < numCourses; i++) {
            if (inDegree[i] == 0) 
                q.add(i);
        }

        int completedCourses = 0;

        // Process the queue to reduce in-degrees and enqueue new nodes with zero in-degree
        while (!q.isEmpty()) {
            int currCourse = q.poll();
            completedCourses++;

            for (int nextCourse : adj.get(currCourse)) {
                inDegree[nextCourse]--;
                if (inDegree[nextCourse] == 0) 
                    q.add(nextCourse);
            }
        }

        // Check if all courses are completed
        return completedCourses == numCourses;
    }
}

